class Solution {
public:
    vector<vector<int>> generate(int numRows) {
        vector<vector<int>> res;
        if (numRows == 0) return res;
        res.push_back({1});
        for (int i = 1; i < numRows; i++) {
            vector<int> row = {1};
            auto& prev = res.back();
            for (int j = 1; j < i; j++)
                row.push_back(prev[j - 1] + prev[j]);
            row.push_back(1);
            res.push_back(row);
        }
        return res;
    }
};
